  const data = new Float32Array(S * S);
  for (let i = 0; i < S; i++) {
    for (let j = 0; j < S; j++) {
      data[i * S + j] = j > i ? -10000 : 0;
    }
  }
  return new Tensor(data, [S, S]);
}

